import Button from "@/components/Button/Button";
import { InputField } from "@/components/Form/InputField";
import AdminLayout from "@/components/Layout/AdminLayout";
import Table from "@/components/Table/Table";
import { apiBaseUrl } from "@/config";
import { User } from "@/types";
import axios from "axios";
import React, { useEffect, useState } from "react";

const ManageShipping = () => {
  const [shippingData, setShippingData] = useState<User[]>([]);
  const fetchShipping = async () => {
    try {
      const response = await axios.get(`${apiBaseUrl}/shipping`);
      if (response.status != 200) {
        throw new Error(`Something bad happened, ${response.statusText}`);
      }
      console.log(response.data);
      setShippingData(response.data);
    } catch (error) {
      console.error(error);
    }
  };

  useEffect(() => {
    fetchShipping();
  }, []);

  return (
    <AdminLayout>
      <h1 className="uppercase font-semibold text-2xl text-black pt-14">
        Manage Shipping List
      </h1>
      <div className="mt-5 flex flex-col">
        <div className="w-full flex justify-end">
          <div className="w-72">
            <InputField
              type="text"
              name="filter"
              variants="small"
              placeholder="Search by name"
              value={""}
              onChange={() => {}}
              err=""
            />
          </div>
        </div>

        <Table />

        {/* <div className="flex justify-end mt-4">
          <div className="flex gap-1">
            <Button variants="bordered" onClick={() => {}}>{`<<`}</Button>
            <Button variants="bordered" onClick={() => {}}>{`<`}</Button>

            <Button variants="bordered" onClick={() => {}}>{`>`}</Button>
            <Button variants="bordered" onClick={() => {}}>{`>>`}</Button>
          </div>
        </div> */}
      </div>
    </AdminLayout>
  );
};

export default ManageShipping;
